// signature is documented in PNEUMA_CONTRACTS.md. Re-exported at the crate
// root by `lib.rs`, but we go through the module path so the dependency is
// visible at a glance.
use crate::math_pneuma::cross_attention;
// AGENT-STUB: Agent D delivers `WhisperConfig` and `whisper_tensor_name` in
// `loader_whisper.rs`. Until that file lands, this import will not resolve;
